/// Use DEFAULT to denote any turns which don't specify fields for turn and
/// CUSTOM to denote any turns with custom field types.
#[derive(Clone, Copy, Debug, PartialEq, Eq, Hash, PartialOrd, Ord, ::prost::Enumeration)]
#[repr(i32)]
pub enum Fields {
    Default = 0,
    Spelling = 1,
    Alphanum = 3,
    Numeric = 4,
    Datetime = 5,
    YesOrNo = 6,
    Custom = 7,
    Address = 8,
}
impl Fields {
    /// String value of the enum field names used in the ProtoBuf definition.
    ///
    /// The values are not transformed in any way and thus are considered stable
    /// (if the ProtoBuf definition does not change) and safe for programmatic use.
    pub fn as_str_name(&self) -> &'static str {
        match self {
            Self::Default => "DEFAULT",
            Self::Spelling => "SPELLING",
            Self::Alphanum => "ALPHANUM",
            Self::Numeric => "NUMERIC",
            Self::Datetime => "DATETIME",
            Self::YesOrNo => "YES_OR_NO",
            Self::Custom => "CUSTOM",
            Self::Address => "ADDRESS",
        }
    }
    /// Creates an enum from field names used in the ProtoBuf definition.
    pub fn from_str_name(value: &str) -> ::core::option::Option<Self> {
        match value {
            "DEFAULT" => Some(Self::Default),
            "SPELLING" => Some(Self::Spelling),
            "ALPHANUM" => Some(Self::Alphanum),
            "NUMERIC" => Some(Self::Numeric),
            "DATETIME" => Some(Self::Datetime),
            "YES_OR_NO" => Some(Self::YesOrNo),
            "CUSTOM" => Some(Self::Custom),
            "ADDRESS" => Some(Self::Address),
            _ => None,
        }
    }
}
